mapper.sql:


where 1 = 1




  and tei.id = #{criteria.id,jdbcType=BIGINT}




  and (tei.mail_subject like #{criteria.blurry,jdbcType=VARCHAR}
       or tei.mail_content like #{criteria.blurry,jdbcType=VARCHAR}
      )




  and tei.status = #{criteria.status,jdbcType=VARCHAR}




  and tei.send_to like #{criteria.sendTo,jdbcType=VARCHAR}




  and tei.send_date >= #{criteria.startTime,jdbcType=TIMESTAMP}




  and tei.send_date <= #{criteria.endTime,jdbcType=TIMESTAMP}




  and tei.planned_date >= #{criteria.planStartTime,jdbcType=TIMESTAMP}




  and tei.planned_date <= #{criteria.planEndTime,jdbcType=TIMESTAMP}
